cardCss:
/*
 * POKEMON RBY / PIXEL UI
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Game Boy Red/Blue/Yellow era — 4-shade monochrome LCD display,
 *             chunky pixel font, battle menu boxes
 * Fonts     : Press Start 2P — pixel-exact Game Boy style
 * Palette   : #ffffff white · #a9a9a9 light gray · #545454 dark gray · #000000 black
 * Background: solid GB screen green or dark battle field
 * Filter    : SVG feColorMatrix desaturate + feComponentTransfer discrete
 *             maps any image to exact 4-shade GB palette
 * Scanlines : CSS repeating-linear-gradient at 2px — subtle LCD grid effect
 * Animation : blinking _ cursor via opacity keyframes (0.8s)
 */

@import url("https://fonts.googleapis.com/css2?family=Press+Start+2P&display=swap");
/* https://fontlibrary.org/en/font/gnu-unifont */
@font-face {
  font-family: UnifontMedium;
  src: url("https://cdn.jsdelivr.net/gh/avidrucker/anki-card-test-1/public/UnifontMedium.woff")
    format("woff");
}

:root {
  --gb-white: #ffffff;
  --gb-light: #a9a9a9;
  --gb-dark:  #545454;
  --gb-black: #000000;
}

html, body, div#qa { height: 100%; }

.card {
  background: var(--gb-black);
  min-height: 100%;
  font-family: "Press Start 2P", monospace;
  image-rendering: pixelated;
}

.off-screen { position: absolute; left: -9999px; }

.gb-card {
  min-height: 100%;
  display: flex;
  flex-direction: column;
  background: var(--gb-black);
  box-sizing: border-box;
  caret-color: var(--gb-dark);
}

/* ── BATTLE ZONE (top half) ── */
.gb-battle-zone {
  flex: 1;
  background: var(--gb-dark);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 1rem;
  border-bottom: 4px solid var(--gb-black);
  min-height: 10rem;
  position: relative;
}

.gb-wild-banner {
  font-family: "Press Start 2P", monospace;
  font-size: 1.80rem;
  color: var(--gb-white);
  letter-spacing: 0.05em;
  margin-bottom: 0.3rem;
  text-transform: uppercase;
}

.gb-sprite-zone { margin-top: 0.8rem; }

.gb-sprite-zone img {
  max-height: 16rem;
  max-width: 100%;
  object-fit: contain;
  filter: url(#gb-palette);
  image-rendering: pixelated;
}

/* ── MENU BOX (bottom half) ── */
.gb-menu-box {
  background: var(--gb-white);
  border: 4px solid var(--gb-black);
  outline: 2px solid var(--gb-dark);
  outline-offset: -8px;
  padding: 1rem 1.2rem 1.2rem;
  position: relative;
  overflow: hidden;
}

.gb-scanlines {
  position: absolute;
  inset: 0;
  background: repeating-linear-gradient(
    to bottom,
    transparent,
    transparent 1px,
    rgba(0,0,0,0.08) 1px,
    rgba(0,0,0,0.08) 2px
  );
  pointer-events: none;
  z-index: 0;
}

.gb-prompt {
  font-family: "Press Start 2P", monospace;
  font-size: 0.9rem;
  color: var(--gb-black);
  margin: 0 0 0.8rem;
  line-height: 1.8;
  position: relative;
  z-index: 1;
}

.gb-term {
  font-family: "UnifontMedium", monospace;
  font-size: 3rem;
  color: var(--gb-black);
  margin: 0 0 0.5rem;
  line-height: 1.6;
  position: relative;
  z-index: 1;
}

.gb-reading {
  font-family: "UnifontMedium", monospace;
  font-size: 1.95rem;
  color: var(--gb-dark);
  margin: 0 0 0.3rem;
  position: relative;
  z-index: 1;
}

.gb-translation {
  font-family: "Press Start 2P", monospace;
  font-size: 1.80rem;
  color: var(--gb-black);
  margin: 0 0 0.2rem;
  line-height: 1.8;
  position: relative;
  z-index: 1;
}

.gb-transliteration {
  font-family: "UnifontMedium", monospace;
  font-size: 1.65rem;
  color: var(--gb-dark);
  font-style: italic;
  margin: 0;
  position: relative;
  z-index: 1;
}

.gb-tags {
  font-family: "UnifontMedium", monospace;
  font-size: 1.50rem;
  color: var(--gb-dark);
  opacity: 0.55;
  margin: 0.4rem 0 0;
  position: relative;
  z-index: 1;
}

.gb-rule { border: none; border-top: 2px solid var(--gb-dark); margin: 0.5rem 0; position: relative; z-index: 1; }

.gb-input-wrap { margin-bottom: 0.5rem; position: relative; z-index: 1; }
.gb-input-wrap input {
  font-family: "Press Start 2P", monospace;
  font-size: 1rem;
  background: transparent;
  border: 2px solid var(--gb-black);
  color: var(--gb-dark);
  width: 100%;
  padding: 0.4rem 1.4rem 0.4rem 0.5rem;
  image-rendering: pixelated;
  box-sizing: border-box;
  caret-color: var(--gb-dark);
}
.gb-input-wrap input:focus { outline: none; border-color: var(--gb-dark); background: transparent; color: var(--gb-dark); }
.gb-input-wrap input::placeholder { color: var(--gb-dark); opacity: 0.6; }
.gb-input-wrap input:focus::placeholder { color: transparent; }

.gb-hint-wrap { margin-top: 0.4rem; position: relative; z-index: 1; }
.gb-hint-link { font-family: "Press Start 2P", monospace; font-size: 0.85rem; color: var(--gb-dark); text-decoration: underline; }
.gb-hint-text { font-family: "Press Start 2P", monospace; font-size: 0.9rem; color: var(--gb-dark); margin-top: 0.3rem; line-height: 1.8; }



@keyframes gb-blink {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0; }
}

.gb-audio { margin: 0 0 0.2rem; position: relative; z-index: 1; }

.append-play-btn-text a::after { content: "▶"; color: var(--gb-white); font-size: 3.60rem; }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-family: "UnifontMedium", monospace; font-size: 6rem; cursor: pointer; color: var(--gb-white); }

.gb-front .gb-wild-banner { font-size: 0.9rem; line-height: 1.5; }
